  app.post("/api/bookings/:id/join", isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const bookingId = req.params.id;

      const booking = await storage.getBooking(bookingId);
      if (!booking) return res.status(404).json({ message: "Session not found" });
      if (!booking.maxParticipants) return res.status(400).json({ message: "This is not a group session" });
      if (!["CONFIRMED", "PENDING"].includes(booking.status)) {
        return res.status(400).json({ message: "This session is no longer available" });
      }

      const participants = await storage.getBookingParticipants(bookingId);
      if (participants.length >= booking.maxParticipants) {
        return res.status(409).json({ message: "This session is full" });
      }

      const alreadyJoined = participants.some(p => p.userId === userId && !p.participantName);
      const participantNames: string[] = req.body.participantNames || [];

      const namesToAdd = participantNames.length > 0
        ? participantNames.filter(n => n.trim())
        : [null];

      const totalAfterJoin = participants.length + namesToAdd.length;
      if (totalAfterJoin > booking.maxParticipants) {
        return res.status(409).json({ message: `Only ${booking.maxParticipants - participants.length} spots remaining` });
      }

      if (participantNames.length === 0 && alreadyJoined) {
        return res.status(409).json({ message: "You have already joined this session" });
      }

      const added = [];
      for (const name of namesToAdd) {
        const p = await storage.addBookingParticipant({
          bookingId,
          userId,
          ...(name ? { participantName: name.trim() } : {}),
        });
        added.push(p);
      }

      try {
        const coachProfile = await storage.getCoachProfile(booking.coachId);
        const service = await storage.getService(booking.serviceId);
        const joiningUser = await storage.getUser(userId);
        if (coachProfile && joiningUser) {
          const participantName = namesToAdd.filter(Boolean).length > 0
            ? namesToAdd.filter(Boolean).join(", ")
            : `${joiningUser.firstName || ""} ${joiningUser.lastName || ""}`.trim();
          const coachName = `${coachProfile.user?.firstName || ""} ${coachProfile.user?.lastName || ""}`.trim();
          const tz = coachProfile.timezone || "America/New_York";
          const sessionName = service?.name || "Group Session";
          const { sendGroupSessionJoinNotification, sendGroupSessionJoinConfirmation } = await import("./email");
          const grpOrgB = await getOrgBranding(coachProfile.organizationId);
          if (coachProfile.user?.email) {
            sendGroupSessionJoinNotification(
              coachProfile.user.email,
              coachProfile.user.firstName || "Coach",
              participantName || "A user",
              sessionName,
              booking.startAt,
              booking.endAt,
              booking.location || undefined,
              tz,
              grpOrgB
            ).catch(() => {});
          }
          if (joiningUser.email) {
            sendGroupSessionJoinConfirmation(
              joiningUser.email,
              joiningUser.firstName || "there",
              coachName || "Your Coach",
              sessionName,
              booking.startAt,
              booking.endAt,
              booking.location || undefined,
              tz,
              grpOrgB
            ).catch(() => {});
          }
        }
      } catch (emailErr) {
        console.error("Error sending group join notification:", emailErr);
      }

      res.json(added.length === 1 ? added[0] : added);
    } catch (error) {
      console.error("Error joining session:", error);
      res.status(500).json({ message: "Failed to join session" });
    }
  });

  app.delete("/api/bookings/:id/leave", isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const bookingId = req.params.id;

      // Fetch booking to validate cancellation window and existence
      const booking = await storage.getBooking(bookingId);
      if (!booking) {
        return res.status(404).json({ message: "Session not found" });
      }

      // Block cancellation once session has started
      const sessionStart = new Date(booking.startAt as any);
      if (new Date() >= sessionStart) {
        return res.status(400).json({ message: "Cannot cancel after the session has already started" });
      }

      // Verify the user is actually registered in this session
      const participants = await storage.getBookingParticipants(bookingId);
      const isParticipant = participants.some((p: any) => p.userId === userId);
      if (!isParticipant) {
        return res.status(403).json({ message: "You are not registered in this session" });
      }

      await storage.removeBookingParticipant(bookingId, userId);

      // Waitlist automation: auto-promote first person waiting
      try {
        const { sql: sqlWL } = await import("drizzle-orm");
        const wlResult = await db.execute(sqlWL`
          SELECT * FROM session_waitlists
          WHERE booking_id = ${bookingId}
          ORDER BY created_at ASC
          LIMIT 1
        `);
        const rows = Array.isArray(wlResult) ? wlResult : ((wlResult as any).rows || []);
        const next = rows[0];
        if (next) {
          await storage.addBookingParticipant({
            bookingId,
            userId: next.user_id as string,
            ...(next.participant_name ? { participantName: next.participant_name as string } : {}),
          } as any);
          await db.execute(sqlWL`DELETE FROM session_waitlists WHERE id = ${next.id}`);
          console.log(`[Waitlist] Auto-promoted user ${next.user_id} to booking ${bookingId}`);
        }
      } catch (wlErr) {
        console.error("[Waitlist] Auto-promotion error (non-fatal):", wlErr);
      }

      res.json({ success: true });
    } catch (error) {
      console.error("Error leaving session:", error);
      res.status(500).json({ message: "Failed to leave session" });
    }
  });

  // ===== SESSION WAITLIST (group sessions) =====
  const initSessionWaitlistsTable = async () => {
    const { db: dbRef } = await import("./db");
    const { sql: sqlRef } = await import("drizzle-orm");
    await dbRef.execute(sqlRef`
      CREATE TABLE IF NOT EXISTS session_waitlists (
        id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid(),
        booking_id VARCHAR NOT NULL REFERENCES bookings(id) ON DELETE CASCADE,
        user_id VARCHAR NOT NULL REFERENCES users(id),
        participant_name VARCHAR,
        created_at TIMESTAMP DEFAULT NOW(),
        UNIQUE(booking_id, user_id)
      )
    `);
  };

  app.get("/api/bookings/:id/waitlist", async (req: any, res) => {
    try {
      await initSessionWaitlistsTable();
      const { db: dbRef } = await import("./db");
      const { sql: sqlRef } = await import("drizzle-orm");
      const result = await dbRef.execute(sqlRef`
        SELECT sw.*, u.first_name, u.last_name, u.profile_image_url
        FROM session_waitlists sw
        LEFT JOIN users u ON sw.user_id = u.id
        WHERE sw.booking_id = ${req.params.id}
        ORDER BY sw.created_at ASC
      `);
      const rows = Array.isArray(result) ? result : ((result as any).rows || []);
      res.json(rows);
    } catch (error) {
      console.error("Error fetching session waitlist:", error);
      res.status(500).json({ message: "Failed to fetch waitlist" });
    }
  });

  app.post("/api/bookings/:id/waitlist", isAuthenticated, async (req: any, res) => {
    try {
      await initSessionWaitlistsTable();
      const userId = req.user.claims?.sub ?? req.user.id;
      const bookingId = req.params.id;
      const { participantName } = req.body;

      const booking = await storage.getBooking(bookingId);
      if (!booking) return res.status(404).json({ message: "Session not found" });
      if (!["CONFIRMED", "PENDING"].includes(booking.status)) {
        return res.status(400).json({ message: "This session is no longer available" });
      }

      const { db: dbRef } = await import("./db");
      const { sql: sqlRef } = await import("drizzle-orm");

      const existing = await dbRef.execute(sqlRef`
        SELECT id FROM session_waitlists WHERE booking_id = ${bookingId} AND user_id = ${userId}
      `);
      const existingRows = Array.isArray(existing) ? existing : ((existing as any).rows || []);
      if (existingRows.length > 0) {
        return res.status(409).json({ message: "You are already on the waitlist" });
      }

      const result = await dbRef.execute(sqlRef`
        INSERT INTO session_waitlists (booking_id, user_id, participant_name)
        VALUES (${bookingId}, ${userId}, ${participantName || null})
        RETURNING *
      `);
      const rows = Array.isArray(result) ? result : ((result as any).rows || []);
      res.json(rows[0] || { success: true });
    } catch (error) {
      console.error("Error joining session waitlist:", error);
      res.status(500).json({ message: "Failed to join waitlist" });
    }
  });

