  // GET /api/ai-approvals/:id — fetch full proposal detail with lead enrichment
  app.get("/api/ai-approvals/:id", isAuthenticated, requireRole("ADMIN", "COACH"), async (req: any, res) => {
    try {
      const orgId = await getAdminOrgId(req);
      if (!orgId) return res.status(403).json({ message: "Not authorized" });
      const { id } = req.params;
      const [proposal] = await db.select().from(gmailAgentActions)
        .where(and(eq(gmailAgentActions.id, id), eq(gmailAgentActions.orgId, orgId)))
        .limit(1);
      if (!proposal) return res.status(404).json({ message: "Not found" });

      let lead: Record<string, any> | null = null;
      try {
        const { leadCaptureSubmissions, leadIntelligenceProfiles, teamTrainingProspects } = await import("@shared/schema");
        if (proposal.leadId) {
          const [sub] = await db.select().from(leadCaptureSubmissions)
            .where(and(eq(leadCaptureSubmissions.id, proposal.leadId), eq(leadCaptureSubmissions.orgId, orgId)))
            .limit(1);
          if (sub) {
            const [intel] = await db.select().from(leadIntelligenceProfiles)
              .where(eq(leadIntelligenceProfiles.submissionId, sub.id))
              .limit(1).catch(() => [] as any[]);
            lead = {
              name: sub.athleteName ?? sub.parentName ?? null,
              email: sub.email,
              sport: sub.sport,
              grade: sub.grade,
              school: sub.school,
              bookingStatus: sub.bookingStatus,
              pipelineStage: intel?.pipelineStage ?? sub.bookingStatus ?? null,
              leadScore: intel?.leadScore ?? null,
              temperature: intel?.temperature ?? null,
              followUpStage: intel?.followUpStage ?? null,
              lastInteractionAt: intel?.lastInteractionAt ?? sub.lastFollowUpAt ?? null,
              followUpCount: sub.followUpCount ?? 0,
            };
          }
        }
        if (!lead && proposal.dealId) {
          const [prospect] = await db.select().from(teamTrainingProspects)
            .where(and(eq(teamTrainingProspects.id, proposal.dealId), eq(teamTrainingProspects.orgId, orgId)))
            .limit(1);
          if (prospect) {
            lead = {
              name: prospect.decisionMakerName || prospect.contactName || prospect.prospectName || null,
              email: prospect.decisionMakerEmail || prospect.contactEmail || null,
              organization: prospect.prospectName,
              sport: prospect.sport !== "unknown" ? prospect.sport : null,
              city: prospect.city !== "unknown" ? prospect.city : null,
              state: prospect.state !== "unknown" ? prospect.state : null,
              outreachStatus: prospect.outreachStatus,
              lastContactedAt: prospect.lastContactedAt,
              contactQuality: prospect.contactQuality,
            };
          }
        }
      } catch (_) {}

      res.json({ proposal, lead });
    } catch (e: any) {
      res.status(500).json({ message: "Failed to load proposal" });
    }
  });

  app.post("/api/ai-approvals/:id/approve", isAuthenticated, requireRole("ADMIN", "COACH"), async (req: any, res) => {
    try {
      const orgId = await getAdminOrgId(req);
      if (!orgId) return res.status(403).json({ message: "Not authorized" });
      const userId = req.user?.claims?.sub ?? req.user?.id;
      const { id } = req.params;
      const { subject: overrideSubject, body: overrideBody, coachingFeedbackText, feedbackTags } = req.body ?? {};
      const [proposal] = await db.select().from(gmailAgentActions).where(and(eq(gmailAgentActions.id, id), eq(gmailAgentActions.orgId, orgId))).limit(1);
      if (!proposal) return res.status(404).json({ message: "Proposal not found" });
      if (proposal.executedAt) return res.status(409).json({ message: "Already executed" });
      if (!proposal.recipientEmail) return res.status(400).json({ message: "No recipient email" });
      const { checkHumanApprovedSendGuards } = await import("./services/send-guard-service");
      const sendGuard = await checkHumanApprovedSendGuards(orgId, proposal.recipientEmail);
      if (sendGuard.blocked) {
        return res.status(sendGuard.blockType === "emergency_pause" ? 503 : 422).json({ message: sendGuard.reason, blockType: sendGuard.blockType });
      }
      const { gmailSendEmail: sendEmail } = await import("./services/gmail-agent-service");
      const subject = overrideSubject ?? proposal.subject ?? "(no subject)";
      const body = overrideBody ?? proposal.bodyPreview ?? "";
      const { messageId, threadId } = await sendEmail({ orgId, to: proposal.recipientEmail, subject, body, leadId: proposal.leadId ?? undefined, dealId: proposal.dealId ?? undefined });
      const isEdited = !!(overrideBody || overrideSubject);
      const [feedbackRow] = await Promise.all([
        db.insert(agentMessageFeedback).values({ orgId, proposalId: id, leadId: proposal.leadId ?? null, agentName: proposal.createdByAgent ?? null, messageType: proposal.actionType.replace("propose_draft:", ""), originalSubject: proposal.subject ?? null, originalBody: proposal.bodyPreview ?? null, editedSubject: isEdited ? subject : null, editedBody: isEdited ? body : null, decision: isEdited ? "edited_and_approved" : "approved", reviewedBy: userId, outcome: "sent", coachingFeedbackText: coachingFeedbackText ?? null, feedbackTags: feedbackTags ?? null, communicationDomain: proposal.communicationDomain ?? "athlete_lead" } as any).returning(),
        db.update(gmailAgentActions).set({ status: "executed", approvedBy: userId, executedAt: new Date(), result: { messageId, threadId } as any }).where(eq(gmailAgentActions.id, id)),
      ]);
      if (feedbackRow[0]?.id && (coachingFeedbackText || (feedbackTags?.length))) {
        const { extractMessageLearningFromFeedback } = await import("./services/message-learning-service");
        extractMessageLearningFromFeedback(orgId, feedbackRow[0].id).catch(console.error);
      }
      // Track outcome
      const { createOutcomeOnSend } = await import("./services/outcome-intelligence-service");
      createOutcomeOnSend({ orgId, gmailActionId: id, feedbackId: feedbackRow[0]?.id, communicationDomain: proposal.communicationDomain ?? "athlete_lead", messageType: proposal.actionType.replace("propose_draft:", ""), recipientEmail: proposal.recipientEmail ?? undefined, leadId: proposal.leadId ?? undefined, dealId: proposal.dealId ?? undefined }).catch(console.error);
      // Fix 2: wire execution into ai_revenue_events so CEO Heartbeat can attribute by agent/message
      const { logActionAsEvent: _logApprove } = await import("./email-agent/revenue-outcome-engine");
      _logApprove(orgId, { actionType: "outreach_email", actionSource: "manual", prospectId: proposal.leadId ?? undefined, dealId: proposal.dealId ?? undefined, executionLogId: id, outcomeSource: proposal.communicationDomain ?? "athlete_lead" }).catch(console.error);
      res.json({ ok: true, messageId, threadId });
    } catch (e: any) {
      console.error("[ai-approvals] approve error:", e);
      const isGmailErr = e?.message?.toLowerCase().includes("gmail") || e?.message?.toLowerCase().includes("oauth") || e?.message?.toLowerCase().includes("token") || e?.message?.toLowerCase().includes("credentials");
      if (isGmailErr) return res.status(503).json({ message: "Gmail connection error — please reconnect Gmail in Settings.", gmailError: true });
      res.status(500).json({ message: e.message ?? "Failed to approve and send" });
    }
  });

